export const PASSWORD_CONFIRMATION_REQUIRED = "Password confirmation required.";
export const TWO_FACTOR_CONFIRMATION_REQUIRED = "Two factor authentication required.";

export type ConfirmationType = "password" | "two-factor";

type ProtectedAction<T> = () => Promise<T>;
type ConfirmAction = (type: ConfirmationType) => Promise<void>;

export const getRequiredConfirmationType = (error: unknown): ConfirmationType | null => {
    if (!(error instanceof Error)) {
        return null;
    }

    if (error.message === PASSWORD_CONFIRMATION_REQUIRED) {
        return "password";
    }

    if (error.message === TWO_FACTOR_CONFIRMATION_REQUIRED) {
        return "two-factor";
    }

    return null;
};

export async function runConfirmAction<T>(
    action: ProtectedAction<T>,
    confirmAction: ConfirmAction,
): Promise<T> {
    try {
        return await action();
    } catch (error) {
        const confirmationType = getRequiredConfirmationType(error);

        if (!confirmationType) {
            throw error;
        }

        await confirmAction(confirmationType);

        return action();
    }
}

import { describe, expect, it, vi } from "vitest";
import {
  PASSWORD_CONFIRMATION_REQUIRED,
  TWO_FACTOR_CONFIRMATION_REQUIRED,
  runConfirmAction,
} from "./confirm-action";

describe("runConfirmAction", () => {
  it("confirms the password and retries the original action after Laravel asks for password confirmation", async () => {
    const action = vi
      .fn<() => Promise<string>>()
      .mockRejectedValueOnce(new Error(PASSWORD_CONFIRMATION_REQUIRED))
      .mockResolvedValueOnce("registered");
    const confirmAction = vi
      .fn<(type: "password" | "two-factor") => Promise<void>>()
      .mockResolvedValue(undefined);

    await expect(runConfirmAction(action, confirmAction)).resolves.toBe("registered");

    expect(action).toHaveBeenCalledTimes(2);
    expect(confirmAction).toHaveBeenCalledTimes(1);
    expect(confirmAction).toHaveBeenCalledWith("password");
  });

  it("confirms an otp code and retries the original action after Laravel asks for two-factor confirmation", async () => {
    const action = vi
      .fn<() => Promise<string>>()
      .mockRejectedValueOnce(new Error(TWO_FACTOR_CONFIRMATION_REQUIRED))
      .mockResolvedValueOnce("registered");
    const confirmAction = vi
      .fn<(type: "password" | "two-factor") => Promise<void>>()
      .mockResolvedValue(undefined);

    await expect(runConfirmAction(action, confirmAction)).resolves.toBe("registered");

    expect(action).toHaveBeenCalledTimes(2);
    expect(confirmAction).toHaveBeenCalledTimes(1);
    expect(confirmAction).toHaveBeenCalledWith("two-factor");
  });

  it("does not retry errors that are not confirmation requirements", async () => {
    const error = new Error("WebAuthn cancelled");
    const action = vi.fn<() => Promise<string>>().mockRejectedValue(error);
    const confirmAction = vi
      .fn<(type: "password" | "two-factor") => Promise<void>>()
      .mockResolvedValue(undefined);

    await expect(runConfirmAction(action, confirmAction)).rejects.toBe(error);

    expect(action).toHaveBeenCalledTimes(1);
    expect(confirmAction).not.toHaveBeenCalled();
  });
});
